-- Source: scripts/sql/find_duplicate_courses.sql
-- =============================================================================
-- Find likely duplicate courses
-- Purpose: Identify candidate course pairs that may need merging
-- Heuristic: same country + city, with one name containing the other (case-insensitive)
-- =============================================================================

with course_pairs as (
  select
    a.id as a_id,
    a.name as a_name,
    a."approvalStatus" as a_status,
    a."submittedBy" as a_submitter,
    b.id as b_id,
    b.name as b_name,
    b."approvalStatus" as b_status,
    b."submittedBy" as b_submitter,
    a.city,
    a.country
  from public.course a
  join public.course b on
    a.id < b.id
    and a.country = b.country
    and lower(a.city) = lower(b.city)
    and (
      lower(a.name) = lower(b.name)
      or lower(a.name) like '%' || lower(b.name) || '%'
      or lower(b.name) like '%' || lower(a.name) || '%'
    )
)
select
  cp.*,
  (select count(*) from public."teeInfo" t where t."courseId" = cp.a_id) as a_tees,
  (select count(*) from public."teeInfo" t where t."courseId" = cp.b_id) as b_tees,
  (select count(*) from public.round r where r."courseId" = cp.a_id) as a_rounds,
  (select count(*) from public.round r where r."courseId" = cp.b_id) as b_rounds
from course_pairs cp
order by cp.country, cp.city, cp.a_name;

-- Source: scripts/sql/find_unreferenced_archived_tees.sql
-- =============================================================================
-- Find archived tees not referenced by any rounds
-- Purpose: Identify dead data safe to delete (archived tees with no rounds pointing to them)
-- Usage: Run the SELECT first to review, then uncomment the DELETE to clean up
-- =============================================================================

-- Preview: show archived tees with no round, child tee, or submission references
select
  t.id as tee_id,
  t.name as tee_name,
  t.gender,
  t."courseId",
  c.name as course_name,
  t."parentTeeId",
  t."approvalStatus",
  t."submittedBy"
from public."teeInfo" t
left join public.course c on c.id = t."courseId"
where t."isArchived" = true
  and not exists (
    select 1 from public.round r where r."teeId" = t.id
  )
  -- Don't delete if child tees still reference this as their parent
  and not exists (
    select 1 from public."teeInfo" child where child."parentTeeId" = t.id
  )
  -- Don't delete if submissions reference this tee (directly or as parent)
  and not exists (
    select 1 from public.submissions s
    where s."teeId" = t.id or s."parentTeeId" = t.id
  )
order by t."courseId", t.name;

